std::vector<std::vector<double>> matmul(const std::vector<std::vector<double>>& a, const std::vector<std::vector<double>>& b){
    int n = (int)a.size();
    int m = (int)b[0].size();
    int k = (int)b.size();
    std::vector<std::vector<double>> c(n, std::vector<double>(m, 0.0));
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < m; ++j){
            double s = 0.0;
            for (int p = 0; p < k; ++p) s += a[i][p] * b[p][j];
            c[i][j] = s;
        }
    return c;
}

